<?php require_once __DIR__. '/../database.php'; require_once __DIR__. '/../blog-setup.php'; header('Content-Type: application/json'); if ($_SERVER['REQUEST_METHOD']!== 'POST') { http_response_code(405); echo json_encode(['success' => false, 'message' => 'Method not allowed']); exit; } $email = trim($_POST['email']?? ''); if (!filter_var($email, FILTER_VALIDATE_EMAIL)) { http_response_code(400); echo json_encode(['success' => false, 'message' => 'Please enter a valid email address.']); exit; } $database = new Database(); $conn = $database->getConnection(); ensureBlogTables($conn); ensureNewsletterTables($conn); $stmt = $conn->prepare( "INSERT INTO newsletter_subscribers (email, status) VALUES (:email, 'active') ON DUPLICATE KEY UPDATE status = 'active'" ); $stmt->execute([':email' => $email]); echo json_encode(['success' => true, 'message' => 'Thanks for subscribing!']); 

